34	/********************************************************************
35	 * Decode mode bits "01x..." to a bitstream vector
36	 * Apply final correction on the dont care bits by referring to the base mode
37	 *bits from physical mode
38	 *******************************************************************/
39	static std::vector<bool> generate_mode_select_bitstream(
40	  const std::vector<char>& mode_bits,
41	  const std::vector<char>& base_mode_bits = std::vector<char>()) {
42	  std::vector<bool> mode_select_bitstream;
43	
44	  /* In absence of base mode bits, all the mode bits must be valid!
45	   * If a base mode bits is provided, use it to correct the 'x' bits in the mode
46	   * bits */
47	  if (base_mode_bits.empty()) {
48	    for (const char& mode_bit : mode_bits) {
49	      /* Error out for unexpected bits */
50	      if ('0' != mode_bit && '1' != mode_bit) {
51	        VTR_LOG_ERROR(
52	          "Final mode bits still contain dont care bits! Expect [0 | 1]! "
53	          "Please ensure all the operating mode bits and physical mode bits "
54	          "can fully resolve dont care bits!\n");
55	        exit(openfpga::CMD_EXEC_FATAL_ERROR);
56	      }
57	      mode_select_bitstream.push_back('1' == mode_bit);
58	    }
59	  } else {
60	    if (mode_bits.size() != base_mode_bits.size()) {
61	      VTR_LOG_ERROR(
62	        "Physical mode bits (%lu) does not match the size of operating mode "
63	        "bits (%lu)!\n",
64	        base_mode_bits.size(), mode_bits.size());
65	      exit(openfpga::CMD_EXEC_FATAL_ERROR);
66	    }
67	    for (size_t ibit = 0; ibit < mode_bits.size(); ++ibit) {
68	      if (mode_bits[ibit] == 'x') {
69	        mode_select_bitstream.push_back('1' == base_mode_bits[ibit]);
70	      } else if ('0' == mode_bits[ibit] || '1' == mode_bits[ibit]) {
71	        mode_select_bitstream.push_back('1' == mode_bits[ibit]);
72	      } else {
73	        VTR_LOG_ERROR("Invalid final mode bits ('%c')! Expect [0 | 1 | x]!\n",
74	                      mode_bits[ibit]);
75	        exit(openfpga::CMD_EXEC_FATAL_ERROR);
76	      }
77	    }
78	  }
79	
80	  return mode_select_bitstream;
81	}
