83	/********************************************************************
84	 * Generate bitstream for a primitive node and add it to bitstream manager
85	 *******************************************************************/
86	static void build_primitive_bitstream(
87	  BitstreamManager& bitstream_manager,
88	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
89	  const ConfigBlockId& parent_configurable_block,
90	  const ModuleManager& module_manager, const CircuitLibrary& circuit_lib,
91	  const VprDeviceAnnotation& device_annotation, const PhysicalPb& physical_pb,
92	  const PhysicalPbId& primitive_pb_id, t_pb_type* primitive_pb_type,
93	  const VprBitstreamAnnotation& bitstream_annotation,
94	  const bool& pcf_mode_specified, const bool& verbose) {
95	  /* Ensure a valid physical pritimive pb */
96	  if (nullptr == primitive_pb_type) {
97	    VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid primitive_pb_type!\n");
98	    exit(1);
99	  }
100	
101	  CircuitModelId primitive_model =
102	    device_annotation.pb_type_circuit_model(primitive_pb_type);
103	  VTR_ASSERT(CircuitModelId::INVALID() != primitive_model);
104	  VTR_ASSERT(
105	    (CIRCUIT_MODEL_IOPAD == circuit_lib.model_type(primitive_model)) ||
106	    (CIRCUIT_MODEL_HARDLOGIC == circuit_lib.model_type(primitive_model)) ||
107	    (CIRCUIT_MODEL_FF == circuit_lib.model_type(primitive_model)));
108	
109	  /* Find SRAM ports for mode-selection */
110	  std::vector<CircuitPortId> primitive_mode_select_ports =
111	    find_circuit_mode_select_sram_ports(circuit_lib, primitive_model);
112	
113	  /* We may have a port for mode select or not. */
114	  VTR_ASSERT((0 == primitive_mode_select_ports.size()) ||
115	             (1 == primitive_mode_select_ports.size()));
116	
117	  /* Generate bitstream for mode-select ports */
118	  if (0 == primitive_mode_select_ports.size()) {
119	    return; /* Nothing to do, return directly */
120	  }
121	
122	  std::vector<bool> mode_select_bitstream;
123	  if (true == physical_pb.valid_pb_id(primitive_pb_id)) {
124	    mode_select_bitstream = generate_mode_select_bitstream(
125	      physical_pb.mode_bits(primitive_pb_id),
126	      device_annotation.pb_type_mode_bits(primitive_pb_type));
127	    /* If the physical pb contains fixed mode-select bitstream, overload here */
128	    for (const auto& fix_bitstrm :
129	         physical_pb.fixed_mode_select_bitstreams(primitive_pb_id)) {
130	      std::string fixed_mode_select_bitstream = fix_bitstrm.content;
131	      size_t mode_bits_start_index = fix_bitstrm.offset;
132	      /* Ensure the length matches!!! */
133	      if (mode_select_bitstream.size() - mode_bits_start_index <
134	          fixed_mode_select_bitstream.size()) {
135	        VTR_LOG_ERROR(
136	          "Unmatched length of fixed mode_select_bitstream %s!Expected to be "
137	          "less than %ld bits\n",
138	          fixed_mode_select_bitstream.c_str(),
139	          mode_select_bitstream.size() - mode_bits_start_index);
140	        exit(1);
141	      }
142	      /* Overload the bitstream here */
143	      for (size_t bit_index = 0; bit_index < fixed_mode_select_bitstream.size();
144	           ++bit_index) {
145	        VTR_ASSERT('0' == fixed_mode_select_bitstream[bit_index] ||
146	                   '1' == fixed_mode_select_bitstream[bit_index]);
147	        mode_select_bitstream[bit_index + mode_bits_start_index] =
148	          ('1' == fixed_mode_select_bitstream[bit_index]);
149	      }
150	    }
151	  } else { /* get default mode_bits */
152	    mode_select_bitstream = generate_mode_select_bitstream(
153	      device_annotation.pb_type_mode_bits(primitive_pb_type));
154	  }
155	  /* Update mode bits from PCF command */
156	  if (pcf_mode_specified) {
157	    /*default mode bits */
158	    mode_select_bitstream = generate_mode_select_bitstream(
159	      device_annotation.pb_type_mode_bits(primitive_pb_type));
160	
161	    auto pcf_mode_select_bitstream_vec =
162	      bitstream_annotation.pb_type_pcf_mode_bits(primitive_pb_type);
163	
164	    /* Add offset */
165	    auto mode_bits_start_index_vec =
166	      bitstream_annotation.pb_type_pcf_offset(primitive_pb_type);
167	    for (size_t it = 0; it < pcf_mode_select_bitstream_vec.size(); it++) {
168	      auto pcf_mode_select_bitstream = pcf_mode_select_bitstream_vec[it];
169	      auto mode_bits_start_index = mode_bits_start_index_vec[it];
170	      VTR_LOG(" \n Specified pcf mode bits are: %s. Bitstream offset is %d\n",
171	              bitstream_annotation
172	                .pb_type_pcf_mode_bits_to_string(primitive_pb_type)[it]
173	                .c_str(),
174	              mode_bits_start_index);
175	
176	      /* Ensure the length matches!!! */
177	      if (mode_select_bitstream.size() - mode_bits_start_index <
178	          pcf_mode_select_bitstream.size()) {
179	        VTR_LOG_ERROR(
180	          "Unmatched length of pcf mode_select_bitstream %s!Expected to be "
181	          "less than %ld bits\n",
182	          bitstream_annotation
183	            .pb_type_pcf_mode_bits_to_string(primitive_pb_type)[it]
184	            .c_str(),
185	          mode_select_bitstream.size() - mode_bits_start_index);
186	        exit(1);
187	      }
188	      /* Overload the bitstream here */
189	      for (size_t bit_index = 0; bit_index < pcf_mode_select_bitstream.size();
190	           ++bit_index) {
191	        VTR_ASSERT('0' == pcf_mode_select_bitstream[bit_index] ||
192	                   '1' == pcf_mode_select_bitstream[bit_index]);
193	        mode_select_bitstream[bit_index + mode_bits_start_index] =
194	          ('1' == pcf_mode_select_bitstream[bit_index]);
195	      }
196	    }
197	  }
198	
199	  /* Ensure the length of bitstream matches the side of memory circuits */
200	  std::vector<CircuitModelId> sram_models =
201	    find_circuit_sram_models(circuit_lib, primitive_model);
202	  VTR_ASSERT(1 == sram_models.size());
203	  std::string mem_block_name =
204	    generate_memory_module_name(circuit_lib, primitive_model, sram_models[0],
205	                                std::string(MEMORY_MODULE_POSTFIX));
206	  ModuleId mem_module = module_manager.find_module(mem_block_name);
207	  VTR_ASSERT(true == module_manager.valid_module_id(mem_module));
208	  ModulePortId mem_out_port_id = module_manager.find_module_port(
209	    mem_module, generate_configurable_memory_data_out_name());
210	  VTR_ASSERT(
211	    mode_select_bitstream.size() ==
212	    module_manager.module_port(mem_module, mem_out_port_id).get_width());
213	
214	  /* If there is a feedthrough module, we should consider the scoreboard */
215	  std::string feedthru_mem_block_name =
216	    generate_memory_module_name(circuit_lib, primitive_model, sram_models[0],
217	                                std::string(MEMORY_MODULE_POSTFIX), true);
218	  ModuleId feedthru_mem_module =
219	    module_manager.find_module(feedthru_mem_block_name);
220	  if (module_manager.valid_module_id(feedthru_mem_module)) {
221	    auto result = grouped_mem_inst_scoreboard.find(mem_block_name);
222	    if (result == grouped_mem_inst_scoreboard.end()) {
223	      /* Update scoreboard */
224	      grouped_mem_inst_scoreboard[mem_block_name] = 0;
225	    } else {
226	      grouped_mem_inst_scoreboard[mem_block_name]++;
227	      mem_block_name = generate_instance_name(
228	        mem_block_name, grouped_mem_inst_scoreboard[mem_block_name]);
229	    }
230	  }
231	
232	  /* Create a block for the bitstream which corresponds to the memory module
233	   * associated to the LUT */
234	  ConfigBlockId mem_block = bitstream_manager.add_block(mem_block_name);
235	  bitstream_manager.add_child_block(parent_configurable_block, mem_block);
236	
237	  VTR_LOGV(verbose, "Added %lu bits to '%s' under '%s'\n",
238	           mode_select_bitstream.size(),
239	           bitstream_manager.block_name(mem_block).c_str(),
240	           bitstream_manager.block_name(parent_configurable_block).c_str());
241	
242	  /* Add the bitstream to the bitstream manager */
243	  bitstream_manager.add_block_bits(mem_block, mode_select_bitstream);
244	}
