246	/********************************************************************
247	 * This function generates bitstream for a programmable routing
248	 * multiplexer which drives an output pin of physical_pb_graph_node and its the
249	 *input_edges
250	 *
251	 *   src_pb_graph_node.[in|out]_pins ----------------->
252	 *des_pb_graph_node.[in|out]pins
253	 *                                        /|\
254	 *                                         |
255	 *                         input_pins,   edges,       output_pins
256	 *******************************************************************/
257	static void build_physical_block_pin_interc_bitstream(
258	  BitstreamManager& bitstream_manager,
259	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
260	  const ConfigBlockId& parent_configurable_block,
261	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
262	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
263	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
264	  const VprBitstreamAnnotation& bitstream_annotation,
265	  const PhysicalPb& physical_pb, t_pb_graph_pin* des_pb_graph_pin,
266	  t_mode* physical_mode, const std::string& unused_mux_config,
267	  const bool& verbose) {
268	  /* Identify the number of fan-in (Consider interconnection edges of only
269	   * selected mode) */
270	  t_interconnect* cur_interc =
271	    pb_graph_pin_interc(des_pb_graph_pin, physical_mode);
272	  size_t fan_in = pb_graph_pin_inputs(des_pb_graph_pin, cur_interc).size();
273	
274	  if ((nullptr == cur_interc) || (0 == fan_in)) {
275	    /* No interconnection matched */
276	    return;
277	  }
278	
279	  /* Identify pin interconnection type */
280	  enum e_interconnect interc_type =
281	    device_annotation.interconnect_physical_type(cur_interc);
282	  switch (interc_type) {
283	    case DIRECT_INTERC:
284	      /* Nothing to do, return */
285	      break;
286	    case COMPLETE_INTERC:
287	    case MUX_INTERC: {
288	      /* Find the circuit model id of the mux, we need its design technology
289	       * which matters the bitstream generation */
290	      CircuitModelId mux_model =
291	        device_annotation.interconnect_circuit_model(cur_interc);
292	      VTR_ASSERT(CIRCUIT_MODEL_MUX == circuit_lib.model_type(mux_model));
293	
294	      /* Find the input size of the implementation of a routing multiplexer */
295	      size_t datapath_mux_size = fan_in;
296	      VTR_ASSERT(true ==
297	                 valid_mux_implementation_num_inputs(datapath_mux_size));
298	
299	      /* Cache input and output nets */
300	      std::vector<AtomNetId> input_nets;
301	      AtomNetId output_net = AtomNetId::INVALID();
302	
303	      /* Find the path id:
304	       * - if des pb is not valid, this is an unmapped pb, we can set a default
305	       * path_id
306	       * - There is no net mapped to des_pb_graph_pin we use default path id
307	       * - There is a net mapped to des_pin_graph_pin: we find the path id
308	       */
309	      const PhysicalPbId& des_pb_id =
310	        physical_pb.find_pb(des_pb_graph_pin->parent_node);
311	      size_t mux_input_pin_id = 0;
312	      if (true != physical_pb.valid_pb_id(des_pb_id)) {
313	        mux_input_pin_id = DEFAULT_PATH_ID;
314	      } else if (AtomNetId::INVALID() == physical_pb.pb_graph_pin_atom_net(
315	                                           des_pb_id, des_pb_graph_pin)) {
316	        mux_input_pin_id = DEFAULT_PATH_ID;
317	      } else {
318	        output_net =
319	          physical_pb.pb_graph_pin_atom_net(des_pb_id, des_pb_graph_pin);
320	
321	        for (t_pb_graph_pin* src_pb_graph_pin :
322	             pb_graph_pin_inputs(des_pb_graph_pin, cur_interc)) {
323	          const PhysicalPbId& src_pb_id =
324	            physical_pb.find_pb(src_pb_graph_pin->parent_node);
325	          input_nets.push_back(
326	            physical_pb.pb_graph_pin_atom_net(src_pb_id, src_pb_graph_pin));
327	        }
328	
329	        for (t_pb_graph_pin* src_pb_graph_pin :
330	             pb_graph_pin_inputs(des_pb_graph_pin, cur_interc)) {
331	          const PhysicalPbId& src_pb_id =
332	            physical_pb.find_pb(src_pb_graph_pin->parent_node);
333	          /* If the src pb id is not valid, we bypass it */
334	          if ((true == physical_pb.valid_pb_id(src_pb_id)) &&
335	              (AtomNetId::INVALID() != output_net) &&
336	              (physical_pb.pb_graph_pin_atom_net(src_pb_id, src_pb_graph_pin) ==
337	               output_net)) {
338	            break;
339	          }
340	          mux_input_pin_id++;
341	        }
342	        VTR_ASSERT(mux_input_pin_id <= fan_in);
343	        /* Unmapped pin, use default path id */
344	        if (fan_in == mux_input_pin_id) {
345	          mux_input_pin_id = DEFAULT_PATH_ID;
346	        }
347	      }
348	
349	      /* Overwrite the default path if defined in bitstream annotation */
350	      if ((size_t(DEFAULT_PATH_ID) == mux_input_pin_id) &&
351	          (mux_input_pin_id !=
352	           bitstream_annotation.interconnect_default_path_id(cur_interc))) {
353	        mux_input_pin_id =
354	          bitstream_annotation.interconnect_default_path_id(cur_interc);
355	      }
356	
357	      /* Generate bitstream depend on both technology and structure of this MUX
358	       */
359	      std::vector<bool> mux_bitstream =
360	        build_mux_bitstream(circuit_lib, mux_model, mux_lib, datapath_mux_size,
361	                            mux_input_pin_id, unused_mux_config);
362	
363	      /* Create the block denoting the memory instances that drives this node in
364	       * physical_block */
365	      std::string mem_block_name = generate_pb_memory_instance_name(
366	        GRID_MEM_INSTANCE_PREFIX, des_pb_graph_pin, std::string(""));
367	
368	      /* Find the module in module manager and ensure the bitstream size
369	       * matches! */
370	      std::string mem_module_name =
371	        generate_mux_subckt_name(circuit_lib, mux_model, datapath_mux_size,
372	                                 std::string(MEMORY_MODULE_POSTFIX));
373	      mem_module_name = module_name_map.name(mem_module_name);
374	      ModuleId mux_mem_module = module_manager.find_module(mem_module_name);
375	      VTR_ASSERT(true == module_manager.valid_module_id(mux_mem_module));
376	      ModulePortId mux_mem_out_port_id = module_manager.find_module_port(
377	        mux_mem_module, generate_configurable_memory_data_out_name());
378	      VTR_ASSERT(mux_bitstream.size() ==
379	                 module_manager.module_port(mux_mem_module, mux_mem_out_port_id)
380	                   .get_width());
381	
382	      /* If there is a feedthrough module, we should consider the scoreboard */
383	      std::string feedthru_mem_block_name = generate_mux_subckt_name(
384	        circuit_lib, mux_model, datapath_mux_size,
385	        std::string(MEMORY_FEEDTHROUGH_MODULE_POSTFIX));
386	      if (module_name_map.name_exist(feedthru_mem_block_name)) {
387	        feedthru_mem_block_name = module_name_map.name(feedthru_mem_block_name);
388	      }
389	      ModuleId feedthru_mem_module =
390	        module_manager.find_module(feedthru_mem_block_name);
391	      if (module_manager.valid_module_id(feedthru_mem_module)) {
392	        auto result = grouped_mem_inst_scoreboard.find(mem_block_name);
393	        if (result == grouped_mem_inst_scoreboard.end()) {
394	          /* Update scoreboard */
395	          grouped_mem_inst_scoreboard[mem_block_name] = 0;
396	        } else {
397	          grouped_mem_inst_scoreboard[mem_block_name]++;
398	          mem_block_name = generate_instance_name(
399	            mem_block_name, grouped_mem_inst_scoreboard[mem_block_name]);
400	        }
401	      }
402	      ConfigBlockId mux_mem_block = bitstream_manager.add_block(mem_block_name);
403	      bitstream_manager.add_child_block(parent_configurable_block,
404	                                        mux_mem_block);
405	
406	      VTR_LOGV(verbose, "Added %lu bits to '%s' under '%s'\n",
407	               mux_bitstream.size(),
408	               bitstream_manager.block_name(mux_mem_block).c_str(),
409	               bitstream_manager.block_name(parent_configurable_block).c_str());
410	
411	      /* Add the bistream to the bitstream manager */
412	      bitstream_manager.add_block_bits(mux_mem_block, mux_bitstream);
413	      /* Record path ids, input and output nets */
414	      bitstream_manager.add_path_id_to_block(mux_mem_block, mux_input_pin_id);
415	
416	      /* Add input nets */
417	      std::string input_net_ids;
418	
419	      bool need_splitter = false;
420	      for (const AtomNetId& input_net : input_nets) {
421	        /* Add a space as a splitter*/
422	        if (true == need_splitter) {
423	          input_net_ids += std::string(" ");
424	        }
425	        if (true == atom_ctx.netlist().valid_net_id(input_net)) {
426	          input_net_ids += atom_ctx.netlist().net_name(input_net);
427	        } else {
428	          input_net_ids += std::string("unmapped");
429	        }
430	        need_splitter = true;
431	      }
432	      bitstream_manager.add_input_net_id_to_block(mux_mem_block, input_net_ids);
433	
434	      /* Add output nets */
435	      std::string output_net_ids;
436	      if (true == atom_ctx.netlist().valid_net_id(output_net)) {
437	        output_net_ids += atom_ctx.netlist().net_name(output_net);
438	      } else {
439	        output_net_ids += std::string("unmapped");
440	      }
441	      bitstream_manager.add_output_net_id_to_block(mux_mem_block,
442	                                                   output_net_ids);
443	
444	      break;
445	    }
446	    default:
447	      VTR_LOGF_ERROR(__FILE__, __LINE__,
448	                     "Invalid interconnection type for %s (Arch[LINE%d])!\n",
449	                     cur_interc->name.c_str(), cur_interc->line_num);
450	      exit(1);
451	  }
452	}
