454	/********************************************************************
455	 * This function generates bitstream for the programmable routing
456	 * multiplexers in a pb_graph node
457	 *******************************************************************/
458	static void build_physical_block_interc_port_bitstream(
459	  BitstreamManager& bitstream_manager,
460	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
461	  const ConfigBlockId& parent_configurable_block,
462	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
463	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
464	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
465	  const VprBitstreamAnnotation& bitstream_annotation,
466	  t_pb_graph_node* physical_pb_graph_node, const PhysicalPb& physical_pb,
467	  const e_circuit_pb_port_type& pb_port_type, t_mode* physical_mode,
468	  const std::string& unused_mux_config, const bool& verbose) {
469	  switch (pb_port_type) {
470	    case CIRCUIT_PB_PORT_INPUT:
471	      for (int iport = 0; iport < physical_pb_graph_node->num_input_ports;
472	           ++iport) {
473	        for (int ipin = 0; ipin < physical_pb_graph_node->num_input_pins[iport];
474	             ++ipin) {
475	          build_physical_block_pin_interc_bitstream(
476	            bitstream_manager, grouped_mem_inst_scoreboard,
477	            parent_configurable_block, module_manager, module_name_map,
478	            circuit_lib, mux_lib, atom_ctx, device_annotation,
479	            bitstream_annotation, physical_pb,
480	            &(physical_pb_graph_node->input_pins[iport][ipin]), physical_mode,
481	            unused_mux_config, verbose);
482	        }
483	      }
484	      break;
485	    case CIRCUIT_PB_PORT_OUTPUT:
486	      for (int iport = 0; iport < physical_pb_graph_node->num_output_ports;
487	           ++iport) {
488	        for (int ipin = 0;
489	             ipin < physical_pb_graph_node->num_output_pins[iport]; ++ipin) {
490	          build_physical_block_pin_interc_bitstream(
491	            bitstream_manager, grouped_mem_inst_scoreboard,
492	            parent_configurable_block, module_manager, module_name_map,
493	            circuit_lib, mux_lib, atom_ctx, device_annotation,
494	            bitstream_annotation, physical_pb,
495	            &(physical_pb_graph_node->output_pins[iport][ipin]), physical_mode,
496	            unused_mux_config, verbose);
497	        }
498	      }
499	      break;
500	    case CIRCUIT_PB_PORT_CLOCK:
501	      for (int iport = 0; iport < physical_pb_graph_node->num_clock_ports;
502	           ++iport) {
503	        for (int ipin = 0; ipin < physical_pb_graph_node->num_clock_pins[iport];
504	             ++ipin) {
505	          build_physical_block_pin_interc_bitstream(
506	            bitstream_manager, grouped_mem_inst_scoreboard,
507	            parent_configurable_block, module_manager, module_name_map,
508	            circuit_lib, mux_lib, atom_ctx, device_annotation,
509	            bitstream_annotation, physical_pb,
510	            &(physical_pb_graph_node->clock_pins[iport][ipin]), physical_mode,
511	            unused_mux_config, verbose);
512	        }
513	      }
514	      break;
515	    default:
516	      VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid pb port type!\n");
517	      exit(1);
518	  }
519	}
