521	/********************************************************************
522	 * This function generates bitstream for the programmable routing
523	 * multiplexers in a pb_graph node
524	 *******************************************************************/
525	static void build_physical_block_interc_bitstream(
526	  BitstreamManager& bitstream_manager,
527	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
528	  const ConfigBlockId& parent_configurable_block,
529	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
530	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
531	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
532	  const VprBitstreamAnnotation& bitstream_annotation,
533	  t_pb_graph_node* physical_pb_graph_node, const PhysicalPb& physical_pb,
534	  t_mode* physical_mode, const std::string& unused_mux_config,
535	  const bool& verbose) {
536	  /* Check if the pb_graph node is valid or not */
537	  if (nullptr == physical_pb_graph_node) {
538	    VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid physical_pb_graph_node.\n");
539	    exit(1);
540	  }
541	
542	  /* We check output_pins of physical_pb_graph_node and its the input_edges
543	   * Iterate over the interconnections between outputs of physical_pb_graph_node
544	   * and outputs of child_pb_graph_node
545	   *   child_pb_graph_node.output_pins ----------------->
546	   * physical_pb_graph_node.outpins
547	   *                                        /|\
548	   *                                         |
549	   *                         input_pins,   edges,       output_pins
550	   * Note: it is not applied to primitive pb_type!
551	   */
552	  build_physical_block_interc_port_bitstream(
553	    bitstream_manager, grouped_mem_inst_scoreboard, parent_configurable_block,
554	    module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
555	    device_annotation, bitstream_annotation, physical_pb_graph_node,
556	    physical_pb, CIRCUIT_PB_PORT_OUTPUT, physical_mode, unused_mux_config,
557	    verbose);
558	
559	  /* We check input_pins of child_pb_graph_node and its the input_edges
560	   * Iterate over the interconnections between inputs of physical_pb_graph_node
561	   * and inputs of child_pb_graph_node
562	   *   physical_pb_graph_node.input_pins ----------------->
563	   * child_pb_graph_node.input_pins
564	   *                                        /|\
565	   *                                         |
566	   *                         input_pins,   edges,       output_pins
567	   */
568	  for (int ipb = 0; ipb < physical_mode->num_pb_type_children; ipb++) {
569	    for (int jpb = 0; jpb < physical_mode->pb_type_children[ipb].num_pb;
570	         jpb++) {
571	      t_pb_graph_node* child_pb_graph_node =
572	        &(physical_pb_graph_node
573	            ->child_pb_graph_nodes[physical_mode->index][ipb][jpb]);
574	
575	      /* For each child_pb_graph_node input pins*/
576	      build_physical_block_interc_port_bitstream(
577	        bitstream_manager, grouped_mem_inst_scoreboard,
578	        parent_configurable_block, module_manager, module_name_map, circuit_lib,
579	        mux_lib, atom_ctx, device_annotation, bitstream_annotation,
580	        child_pb_graph_node, physical_pb, CIRCUIT_PB_PORT_INPUT, physical_mode,
581	        unused_mux_config, verbose);
582	      /* For clock pins, we should do the same work */
583	      build_physical_block_interc_port_bitstream(
584	        bitstream_manager, grouped_mem_inst_scoreboard,
585	        parent_configurable_block, module_manager, module_name_map, circuit_lib,
586	        mux_lib, atom_ctx, device_annotation, bitstream_annotation,
587	        child_pb_graph_node, physical_pb, CIRCUIT_PB_PORT_CLOCK, physical_mode,
588	        unused_mux_config, verbose);
589	    }
590	  }
591	}
