593	/********************************************************************
594	 * Generate bitstream for a LUT and add it to bitstream manager
595	 * This function supports both single-output and fracturable LUTs
596	 *******************************************************************/
597	static void build_lut_bitstream(
598	  BitstreamManager& bitstream_manager,
599	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
600	  const ConfigBlockId& parent_configurable_block,
601	  const VprDeviceAnnotation& device_annotation,
602	  const ModuleManager& module_manager, const CircuitLibrary& circuit_lib,
603	  const MuxLibrary& mux_lib, const PhysicalPb& physical_pb,
604	  const PhysicalPbId& lut_pb_id, t_pb_type* lut_pb_type, const bool& verbose) {
605	  /* Ensure a valid physical pritimive pb */
606	  if (nullptr == lut_pb_type) {
607	    VTR_LOGF_ERROR(__FILE__, __LINE__, "Invalid lut_pb_type!\n");
608	    exit(1);
609	  }
610	
611	  CircuitModelId lut_model =
612	    device_annotation.pb_type_circuit_model(lut_pb_type);
613	  VTR_ASSERT(CircuitModelId::INVALID() != lut_model);
614	  VTR_ASSERT(CIRCUIT_MODEL_LUT == circuit_lib.model_type(lut_model));
615	
616	  /* Find the input ports for LUT size, this is used to decode the LUT memory
617	   * bits! */
618	  std::vector<CircuitPortId> model_input_ports =
619	    find_lut_circuit_model_input_port(circuit_lib, lut_model, false);
620	  VTR_ASSERT(1 == model_input_ports.size());
621	  size_t lut_size = circuit_lib.port_size(model_input_ports[0]);
622	
623	  /* Find SRAM ports for truth tables and mode-selection */
624	  std::vector<CircuitPortId> lut_regular_sram_ports =
625	    find_circuit_regular_sram_ports(circuit_lib, lut_model);
626	  std::vector<CircuitPortId> lut_mode_select_ports =
627	    find_circuit_mode_select_sram_ports(circuit_lib, lut_model);
628	  /* We should always 1 regular sram port, where truth table is loaded to */
629	  VTR_ASSERT(1 == lut_regular_sram_ports.size());
630	  /* We may have a port for mode select or not. This depends on if the LUT is
631	   * fracturable or not */
632	  VTR_ASSERT((0 == lut_mode_select_ports.size()) ||
633	             (1 == lut_mode_select_ports.size()));
634	
635	  std::vector<bool> lut_bitstream;
636	  /* Generate bitstream for the LUT */
637	  if (false == physical_pb.valid_pb_id(lut_pb_id)) {
638	    /* An empty pb means that this is an unused LUT,
639	     * we give an empty truth table, which are full of default values (defined
640	     * by users)
641	     */
642	    for (size_t i = 0; i < circuit_lib.port_size(lut_regular_sram_ports[0]);
643	         ++i) {
644	      VTR_ASSERT(
645	        (0 == circuit_lib.port_default_value(lut_regular_sram_ports[0])) ||
646	        (1 == circuit_lib.port_default_value(lut_regular_sram_ports[0])));
647	      lut_bitstream.push_back(
648	        1 == circuit_lib.port_default_value(lut_regular_sram_ports[0]));
649	    }
650	  } else {
651	    VTR_ASSERT(true == physical_pb.valid_pb_id(lut_pb_id));
652	
653	    /* Find MUX graph correlated to the LUT */
654	    MuxId lut_mux_id = mux_lib.mux_graph(lut_model, (size_t)pow(2., lut_size));
655	    const MuxGraph& mux_graph = mux_lib.mux_graph(lut_mux_id);
656	    /* Ensure the LUT MUX has the expected input and SRAM port sizes */
657	    VTR_ASSERT(mux_graph.num_memory_bits() == lut_size);
658	    VTR_ASSERT(mux_graph.num_inputs() == (size_t)pow(2., lut_size));
659	    /* Generate LUT bitstream */
660	    lut_bitstream = build_frac_lut_bitstream(
661	      circuit_lib, mux_graph, device_annotation,
662	      physical_pb.truth_tables(lut_pb_id),
663	      circuit_lib.port_default_value(lut_regular_sram_ports[0]));
664	    /* If the physical pb contains fixed bitstream, overload here */
665	    for (const auto& fix_bitstrm : physical_pb.fixed_bitstreams(lut_pb_id)) {
666	      std::string fixed_bitstream = fix_bitstrm.content;
667	      size_t start_index = fix_bitstrm.offset;
668	      /* Ensure the length matches!!! */
669	      if (lut_bitstream.size() - start_index < fixed_bitstream.size()) {
670	        VTR_LOG_ERROR(
671	          "Unmatched length of fixed bitstream %s!Expected to be less than %ld "
672	          "bits\n",
673	          fixed_bitstream.c_str(), lut_bitstream.size() - start_index);
674	        exit(1);
675	      }
676	      /* Overload the bitstream here */
677	      for (size_t bit_index = 0; bit_index < lut_bitstream.size();
678	           ++bit_index) {
679	        VTR_ASSERT('0' == fixed_bitstream[bit_index] ||
680	                   '1' == fixed_bitstream[bit_index]);
681	        lut_bitstream[bit_index + start_index] =
682	          ('1' == fixed_bitstream[bit_index]);
683	      }
684	    }
685	  }
686	
687	  /* Generate bitstream for mode-select ports */
688	  if (0 != lut_mode_select_ports.size()) {
689	    std::vector<bool> mode_select_bitstream;
690	    if (true == physical_pb.valid_pb_id(lut_pb_id)) {
691	      mode_select_bitstream = generate_mode_select_bitstream(
692	        physical_pb.mode_bits(lut_pb_id),
693	        device_annotation.pb_type_mode_bits(lut_pb_type));
694	
695	      /* If the physical pb contains fixed mode-select bitstream, overload here
696	       */
697	      for (const auto& fix_bitstrm :
698	           physical_pb.fixed_mode_select_bitstreams(lut_pb_id)) {
699	        std::string fixed_mode_select_bitstream = fix_bitstrm.content;
700	        size_t mode_bits_start_index = fix_bitstrm.offset;
701	        /* Ensure the length matches!!! */
702	        if (mode_select_bitstream.size() - mode_bits_start_index <
703	            fixed_mode_select_bitstream.size()) {
704	          VTR_LOG_ERROR(
705	            "Unmatched length of fixed mode_select_bitstream %s!Expected to be "
706	            "less than %ld bits\n",
707	            fixed_mode_select_bitstream.c_str(),
708	            mode_select_bitstream.size() - mode_bits_start_index);
709	          exit(1);
710	        }
711	        /* Overload the bitstream here */
712	        for (size_t bit_index = 0;
713	             bit_index < fixed_mode_select_bitstream.size(); ++bit_index) {
714	          VTR_ASSERT('0' == fixed_mode_select_bitstream[bit_index] ||
715	                     '1' == fixed_mode_select_bitstream[bit_index]);
716	          mode_select_bitstream[bit_index + mode_bits_start_index] =
717	            ('1' == fixed_mode_select_bitstream[bit_index]);
718	        }
719	      }
720	    } else { /* get default mode_bits */
721	      mode_select_bitstream = generate_mode_select_bitstream(
722	        device_annotation.pb_type_mode_bits(lut_pb_type));
723	    }
724	
725	    /* Conjunct the mode-select bitstream to the lut bitstream */
726	    for (const bool& bit : mode_select_bitstream) {
727	      lut_bitstream.push_back(bit);
728	    }
729	  }
730	
731	  /* Ensure the length of bitstream matches the side of memory circuits */
732	  std::vector<CircuitModelId> sram_models =
733	    find_circuit_sram_models(circuit_lib, lut_model);
734	  VTR_ASSERT(1 == sram_models.size());
735	  std::string mem_block_name = generate_memory_module_name(
736	    circuit_lib, lut_model, sram_models[0], std::string(MEMORY_MODULE_POSTFIX));
737	  ModuleId mem_module = module_manager.find_module(mem_block_name);
738	  VTR_ASSERT(true == module_manager.valid_module_id(mem_module));
739	  ModulePortId mem_out_port_id = module_manager.find_module_port(
740	    mem_module, generate_configurable_memory_data_out_name());
741	  VTR_ASSERT(
742	    lut_bitstream.size() ==
743	    module_manager.module_port(mem_module, mem_out_port_id).get_width());
744	
745	  /* If there is a feedthrough module, we should consider the scoreboard */
746	  std::string feedthru_mem_block_name =
747	    generate_memory_module_name(circuit_lib, lut_model, sram_models[0],
748	                                std::string(MEMORY_MODULE_POSTFIX), true);
749	  ModuleId feedthru_mem_module =
750	    module_manager.find_module(feedthru_mem_block_name);
751	  if (module_manager.valid_module_id(feedthru_mem_module)) {
752	    auto result = grouped_mem_inst_scoreboard.find(mem_block_name);
753	    if (result == grouped_mem_inst_scoreboard.end()) {
754	      /* Update scoreboard */
755	      grouped_mem_inst_scoreboard[mem_block_name] = 0;
756	    } else {
757	      grouped_mem_inst_scoreboard[mem_block_name]++;
758	      mem_block_name = generate_instance_name(
759	        mem_block_name, grouped_mem_inst_scoreboard[mem_block_name]);
760	    }
761	  }
762	
763	  /* Create a block for the bitstream which corresponds to the memory module
764	   * associated to the LUT */
765	  ConfigBlockId mem_block = bitstream_manager.add_block(mem_block_name);
766	  bitstream_manager.add_child_block(parent_configurable_block, mem_block);
767	
768	  VTR_LOGV(verbose, "Added %lu bits to '%s' under '%s'\n", lut_bitstream.size(),
769	           bitstream_manager.block_name(mem_block).c_str(),
770	           bitstream_manager.block_name(parent_configurable_block).c_str());
771	
772	  /* Add the bitstream to the bitstream manager */
773	  bitstream_manager.add_block_bits(mem_block, lut_bitstream);
774	}
