776	/********************************************************************
777	 * This function generates bitstream for a physical block, which is
778	 * a child block of a grid
779	 * This function will follow a recursive way in generating bitstreams
780	 * It will follow the same sequence in visiting all the sub blocks
781	 * in a physical as we did during module generation
782	 *
783	 * Note: if you want to bind your bitstream with a FPGA fabric generated by
784	 *FPGA-X2P Please follow the same sequence in visiting pb_graph nodes!!! For
785	 *more details, you may refer to function rec_build_physical_block_modules()
786	 *******************************************************************/
787	static void rec_build_physical_block_bitstream(
788	  BitstreamManager& bitstream_manager,
789	  std::map<std::string, size_t>& grouped_mem_inst_scoreboard,
790	  const ConfigBlockId& parent_configurable_block,
791	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
792	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
793	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
794	  const VprBitstreamAnnotation& bitstream_annotation, const e_side& border_side,
795	  const PhysicalPb& physical_pb, const PhysicalPbId& pb_id,
796	  t_pb_graph_node* physical_pb_graph_node, const size_t& pb_graph_node_index,
797	  const bool& pcf_mode_specified, const std::string& unused_mux_config,
798	  const bool& verbose) {
799	  /* Get the physical pb_type that is linked to the pb_graph node */
800	  t_pb_type* physical_pb_type = physical_pb_graph_node->pb_type;
801	
802	  /* Find the mode that define_idle_mode*/
803	  t_mode* physical_mode = device_annotation.physical_mode(physical_pb_type);
804	
805	  /* Early exit if this parent module has no configurable child modules */
806	  std::string pb_module_name =
807	    generate_physical_block_module_name(physical_pb_type);
808	  pb_module_name = module_name_map.name(pb_module_name);
809	  ModuleId pb_module = module_manager.find_module(pb_module_name);
810	  VTR_ASSERT(true == module_manager.valid_module_id(pb_module));
811	
812	  /* Skip module with no configurable children */
813	  if (0 == module_manager.num_configurable_children(
814	             pb_module, ModuleManager::e_config_child_type::LOGICAL)) {
815	    return;
816	  }
817	
818	  /* Create a block for the physical block under the grid block in bitstream
819	   * manager */
820	  std::string pb_block_name = generate_physical_block_instance_name(
821	    physical_pb_type, pb_graph_node_index);
822	  /* If there are no physical memory blocks under the current module, use the
823	   * previous module, which is the physical memory block */
824	  ConfigBlockId pb_configurable_block = parent_configurable_block;
825	  if (0 < module_manager.num_configurable_children(
826	            pb_module, ModuleManager::e_config_child_type::PHYSICAL)) {
827	    pb_configurable_block = bitstream_manager.add_block(pb_block_name);
828	    bitstream_manager.add_child_block(parent_configurable_block,
829	                                      pb_configurable_block);
830	    /* Reserve child blocks for new created block */
831	    bitstream_manager.reserve_child_blocks(
832	      parent_configurable_block,
833	      count_module_manager_module_configurable_children(
834	        module_manager, pb_module,
835	        ModuleManager::e_config_child_type::PHYSICAL));
836	  }
837	
838	  /* Recursively finish all the child pb_types*/
839	  if (false == is_primitive_pb_type(physical_pb_type)) {
840	    for (int ipb = 0; ipb < physical_mode->num_pb_type_children; ++ipb) {
841	      for (int jpb = 0; jpb < physical_mode->pb_type_children[ipb].num_pb;
842	           ++jpb) {
843	        PhysicalPbId child_pb = PhysicalPbId::INVALID();
844	        /* Find the child pb that is mapped, and the mapping info is not stored
845	         * in the physical mode ! */
846	        if (true == physical_pb.valid_pb_id(pb_id)) {
847	          child_pb = physical_pb.child(
848	            pb_id, &(physical_mode->pb_type_children[ipb]), jpb);
849	          VTR_ASSERT(true == physical_pb.valid_pb_id(child_pb));
850	        }
851	        /* Go recursively */
852	        rec_build_physical_block_bitstream(
853	          bitstream_manager, grouped_mem_inst_scoreboard, pb_configurable_block,
854	          module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
855	          device_annotation, bitstream_annotation, border_side, physical_pb,
856	          child_pb,
857	          &(physical_pb_graph_node
858	              ->child_pb_graph_nodes[physical_mode->index][ipb][jpb]),
859	          jpb, pcf_mode_specified, unused_mux_config, verbose);
860	      }
861	    }
862	  }
863	
864	  /* Check if this has defined a circuit_model*/
865	  if (true == is_primitive_pb_type(physical_pb_type)) {
866	    CircuitModelId primitive_circuit_model =
867	      device_annotation.pb_type_circuit_model(physical_pb_type);
868	    VTR_ASSERT(CircuitModelId::INVALID() != primitive_circuit_model);
869	    switch (circuit_lib.model_type(primitive_circuit_model)) {
870	      case CIRCUIT_MODEL_LUT:
871	        /* Special case for LUT !!!
872	         * Mapped logical block information is stored in child_pbs of this pb!!!
873	         */
874	        build_lut_bitstream(bitstream_manager, grouped_mem_inst_scoreboard,
875	                            pb_configurable_block, device_annotation,
876	                            module_manager, circuit_lib, mux_lib, physical_pb,
877	                            pb_id, physical_pb_type, verbose);
878	        break;
879	      case CIRCUIT_MODEL_FF:
880	      case CIRCUIT_MODEL_HARDLOGIC:
881	      case CIRCUIT_MODEL_IOPAD:
882	        /* For other types of blocks, we can apply a generic therapy */
883	        build_primitive_bitstream(
884	          bitstream_manager, grouped_mem_inst_scoreboard, pb_configurable_block,
885	          module_manager, circuit_lib, device_annotation, physical_pb, pb_id,
886	          physical_pb_type, bitstream_annotation, pcf_mode_specified, verbose);
887	        break;
888	      default:
889	        VTR_LOGF_ERROR(__FILE__, __LINE__,
890	                       "Unknown circuit model type of pb_type '%s'!\n",
891	                       physical_pb_type->name);
892	        exit(1);
893	    }
894	    /* Finish for primitive node, return */
895	    return;
896	  }
897	
898	  /* Generate the bitstream for the interconnection in this physical block */
899	  build_physical_block_interc_bitstream(
900	    bitstream_manager, grouped_mem_inst_scoreboard, pb_configurable_block,
901	    module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
902	    device_annotation, bitstream_annotation, physical_pb_graph_node,
903	    physical_pb, physical_mode, unused_mux_config, verbose);
904	}
