906	/********************************************************************
907	 * This function generates bitstream for a grid, which could be a
908	 * CLB, a heterogenerous block, an I/O, etc.
909	 * Note that each grid may contain a number of physical blocks,
910	 * this function will iterate over them
911	 *******************************************************************/
912	static void build_physical_block_bitstream(
913	  BitstreamManager& bitstream_manager, const ConfigBlockId& top_block,
914	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
915	  const FabricTile& fabric_tile, const FabricTileId& curr_tile,
916	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
917	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
918	  const VprClusteringAnnotation& cluster_annotation,
919	  const VprPlacementAnnotation& place_annotation,
920	  const VprBitstreamAnnotation& bitstream_annotation, const DeviceGrid& grids,
921	  const size_t& layer, const vtr::Point<size_t>& grid_coord,
922	  const e_side& border_side, const std::string& unused_mux_config,
923	  const bool& verbose) {
924	  /* Create a block for the grid in bitstream manager */
925	  t_physical_tile_type_ptr grid_type = grids.get_physical_type(
926	    t_physical_tile_loc(grid_coord.x(), grid_coord.y(), layer));
927	  std::string grid_module_name_prefix(GRID_MODULE_NAME_PREFIX);
928	
929	  /* Early exit if this parent module has no configurable child modules */
930	  std::string grid_module_name = generate_grid_block_module_name(
931	    grid_module_name_prefix, std::string(grid_type->name), grid_type->is_io(),
932	    border_side);
933	  grid_module_name = module_name_map.name(grid_module_name);
934	  ModuleId grid_module = module_manager.find_module(grid_module_name);
935	  VTR_ASSERT(true == module_manager.valid_module_id(grid_module));
936	
937	  /* Skip module with no configurable children */
938	  if (0 == module_manager.num_configurable_children(
939	             grid_module, ModuleManager::e_config_child_type::LOGICAL)) {
940	    return;
941	  }
942	
943	  vtr::Point<size_t> grid_coord_in_unique_tile = grid_coord;
944	  if (fabric_tile.valid_tile_id(curr_tile)) {
945	    /* For tile modules, need to find the specific instance name under its
946	     * unique tile */
947	    grid_coord_in_unique_tile =
948	      fabric_tile.find_pb_coordinate_in_unique_tile(curr_tile, grid_coord);
949	  }
950	  std::string grid_block_name = generate_grid_block_instance_name(
951	    grid_module_name_prefix, std::string(grid_type->name), grid_type->is_io(),
952	    border_side, grid_coord_in_unique_tile);
953	
954	  ConfigBlockId grid_configurable_block =
955	    bitstream_manager.add_block(grid_block_name);
956	  bitstream_manager.add_child_block(top_block, grid_configurable_block);
957	
958	  /* Reserve child blocks for new created block */
959	  bitstream_manager.reserve_child_blocks(
960	    grid_configurable_block, count_module_manager_module_configurable_children(
961	                               module_manager, grid_module,
962	                               ModuleManager::e_config_child_type::PHYSICAL));
963	
964	  /* Create a dedicated block for the non-unified configurable child */
965	  if (!module_manager.unified_configurable_children(grid_module)) {
966	    VTR_ASSERT(1 ==
967	               module_manager
968	                 .configurable_children(
969	                   grid_module, ModuleManager::e_config_child_type::PHYSICAL)
970	                 .size());
971	    std::string phy_mem_instance_name = module_manager.instance_name(
972	      grid_module,
973	      module_manager.configurable_children(
974	        grid_module, ModuleManager::e_config_child_type::PHYSICAL)[0],
975	      module_manager.configurable_child_instances(
976	        grid_module, ModuleManager::e_config_child_type::PHYSICAL)[0]);
977	    ConfigBlockId grid_grouped_config_block =
978	      bitstream_manager.add_block(phy_mem_instance_name);
979	    VTR_LOGV(
980	      verbose,
981	      "Added grouped configurable memory block '%s' as a child to '%s'\n",
982	      bitstream_manager.block_name(grid_grouped_config_block).c_str(),
983	      bitstream_manager.block_name(grid_configurable_block).c_str());
984	    bitstream_manager.add_child_block(grid_configurable_block,
985	                                      grid_grouped_config_block);
986	    grid_configurable_block = grid_grouped_config_block;
987	  }
988	
989	  /* Iterate over the capacity of the grid
990	   * Now each physical tile may have a number of logical blocks
991	   * OpenFPGA only considers the physical implementation of the tiles.
992	   * So, we do not allow multiple equivalent sites to be defined
993	   * under a physical tile type.
994	   * If you need different equivalent sites, you can always define
995	   * it as a mode under a <pb_type>
996	   */
997	  std::map<std::string, size_t> grouped_mem_inst_scoreboard;
998	  for (size_t z = 0; z < place_annotation.grid_blocks(grid_coord).size(); ++z) {
999	    int sub_tile_index =
1000	      device_annotation.physical_tile_z_to_subtile_index(grid_type, z);
1001	    t_logical_block_type_ptr lb_type =
1002	      device_annotation.physical_equivalent_site(
1003	        grid_type, grid_type->sub_tiles[sub_tile_index].name);
1004	    VTR_ASSERT(lb_type != nullptr);
1005	    bool pcf_mode_specified = false;
1006	    std::array<size_t, 3> pcf_loc = {grid_coord.x(), grid_coord.y(), z};
1007	    if (bitstream_annotation.pcf_coord_pb_type(pcf_loc)) {
1008	      pcf_mode_specified = true;
1009	    }
1010	    /* Bypass empty pb_graph */
1011	    if (nullptr == lb_type->pb_graph_head) {
1012	      continue;
1013	    }
1014	
1015	    if (ClusterBlockId::INVALID() ==
1016	        place_annotation.grid_blocks(grid_coord)[z]) {
1017	      /* Recursively traverse the pb_graph and generate bitstream */
1018	      rec_build_physical_block_bitstream(
1019	        bitstream_manager, grouped_mem_inst_scoreboard, grid_configurable_block,
1020	        module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
1021	        device_annotation, bitstream_annotation, border_side, PhysicalPb(),
1022	        PhysicalPbId::INVALID(), lb_type->pb_graph_head, z, pcf_mode_specified,
1023	        unused_mux_config, verbose);
1024	    } else {
1025	      const PhysicalPb& phy_pb = cluster_annotation.physical_pb(
1026	        place_annotation.grid_blocks(grid_coord)[z]);
1027	
1028	      VTR_LOGV(verbose,
1029	               "Generating bitstream for block (x=%lu, y=%lu, subtile=%lu)\n",
1030	               grid_coord.x(), grid_coord.y(), z);
1031	
1032	      /* Get the top-level node of the pb_graph */
1033	      t_pb_graph_node* pb_graph_head = lb_type->pb_graph_head;
1034	      VTR_ASSERT(nullptr != pb_graph_head);
1035	      const PhysicalPbId& top_pb_id = phy_pb.find_pb(pb_graph_head);
1036	      VTR_ASSERT(phy_pb.valid_pb_id(top_pb_id));
1037	
1038	      /* Recursively traverse the pb_graph and generate bitstream */
1039	      rec_build_physical_block_bitstream(
1040	        bitstream_manager, grouped_mem_inst_scoreboard, grid_configurable_block,
1041	        module_manager, module_name_map, circuit_lib, mux_lib, atom_ctx,
1042	        device_annotation, bitstream_annotation, border_side, phy_pb, top_pb_id,
1043	        pb_graph_head, z, pcf_mode_specified, unused_mux_config, verbose);
1044	      VTR_LOGV(verbose, "Done\n");
1045	    }
1046	  }
1047	}
1048	
1049	/********************************************************************
1050	 * Top-level function of this file:
1051	 * Generate bitstreams for all the grids, including
1052	 * 1. core grids that sit in the center of the fabric
1053	 * 2. side grids (I/O grids) that sit in the borders for the fabric
1054	 *******************************************************************/
1055	void build_grid_bitstream(
1056	  BitstreamManager& bitstream_manager, const ConfigBlockId& top_block,
1057	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
1058	  const FabricTile& fabric_tile, const CircuitLibrary& circuit_lib,
1059	  const MuxLibrary& mux_lib, const DeviceGrid& grids, const size_t& layer,
1060	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
1061	  const VprClusteringAnnotation& cluster_annotation,
1062	  const VprPlacementAnnotation& place_annotation,
1063	  const VprBitstreamAnnotation& bitstream_annotation,
1064	  const std::string& unused_mux_config, const bool& verbose) {
1065	  VTR_LOGV(verbose, "Generating bitstream for core grids...");
1066	
1067	  /* Generate bitstream for the core logic block one by one */
1068	  for (size_t ix = 1; ix < grids.width() - 1; ++ix) {
1069	    for (size_t iy = 1; iy < grids.height() - 1; ++iy) {
1070	      t_physical_tile_loc phy_tile_loc(ix, iy, layer);
1071	      /* Bypass EMPTY grid */
1072	      if (true == is_empty_type(grids.get_physical_type(phy_tile_loc))) {
1073	        continue;
1074	      }
1075	      /* Skip width > 1 or height > 1 tiles (mostly heterogeneous blocks) */
1076	      if ((0 < grids.get_width_offset(phy_tile_loc)) ||
1077	          (0 < grids.get_height_offset(phy_tile_loc))) {
1078	        continue;
1079	      }
1080	      /* Add a grid module to top_module*/
1081	      vtr::Point<size_t> grid_coord(ix, iy);
1082	      /* TODO: If the fabric tile is not empty, find the tile module and create
1083	       * the block accordingly. Also to support future hierarchy changes, when
1084	       * creating the blocks, trace backward until reach the current top block.
1085	       * If any block is missing during the back tracing, create it. */
1086	      ConfigBlockId parent_block = top_block;
1087	      FabricTileId curr_tile =
1088	        fabric_tile.find_tile_by_pb_coordinate(grid_coord);
1089	      if (fabric_tile.valid_tile_id(curr_tile)) {
1090	        vtr::Point<size_t> tile_coord = fabric_tile.tile_coordinate(curr_tile);
1091	        std::string tile_inst_name = generate_tile_module_name(tile_coord);
1092	        parent_block = bitstream_manager.find_or_create_child_block(
1093	          top_block, tile_inst_name);
1094	        VTR_LOGV(verbose,
1095	                 "Add configurable block '%s' as a child under configurable "
1096	                 "block '%s'\n",
1097	                 tile_inst_name.c_str(),
1098	                 bitstream_manager.block_name(top_block).c_str());
1099	      }
1100	
1101	      build_physical_block_bitstream(
1102	        bitstream_manager, parent_block, module_manager, module_name_map,
1103	        fabric_tile, curr_tile, circuit_lib, mux_lib, atom_ctx,
1104	        device_annotation, cluster_annotation, place_annotation,
1105	        bitstream_annotation, grids, layer, grid_coord, NUM_2D_SIDES,
1106	        unused_mux_config, verbose);
1107	    }
1108	  }
1109	  VTR_LOGV(verbose, "Done\n");
1110	
1111	  VTR_LOGV(verbose, "Generating bitstream for I/O grids...");
1112	
1113	  /* Create the coordinate range for each side of FPGA fabric */
1114	  std::map<e_side, std::vector<vtr::Point<size_t>>> io_coordinates =
1115	    generate_perimeter_grid_coordinates(grids);
1116	
1117	  /* Add instances of I/O grids to top_module */
1118	  for (const e_side& io_side : FPGA_SIDES_CLOCKWISE) {
1119	    for (const vtr::Point<size_t>& io_coordinate : io_coordinates[io_side]) {
1120	      t_physical_tile_loc phy_tile_loc(io_coordinate.x(), io_coordinate.y(),
1121	                                       layer);
1122	      /* Bypass EMPTY grid */
1123	      if (true == is_empty_type(grids.get_physical_type(phy_tile_loc))) {
1124	        continue;
1125	      }
1126	      /* Skip height > 1 tiles (mostly heterogeneous blocks) */
1127	      if ((0 < grids.get_width_offset(phy_tile_loc)) ||
1128	          (0 < grids.get_height_offset(phy_tile_loc))) {
1129	        continue;
1130	      }
1131	      /* TODO: If the fabric tile is not empty, find the tile module and create
1132	       * the block accordingly. Also to support future hierarchy changes, when
1133	       * creating the blocks, trace backward until reach the current top block.
1134	       * If any block is missing during the back tracing, create it. */
1135	      ConfigBlockId parent_block = top_block;
1136	      FabricTileId curr_tile =
1137	        fabric_tile.find_tile_by_pb_coordinate(io_coordinate);
1138	      if (fabric_tile.valid_tile_id(curr_tile)) {
1139	        vtr::Point<size_t> tile_coord = fabric_tile.tile_coordinate(curr_tile);
1140	        std::string tile_inst_name = generate_tile_module_name(tile_coord);
1141	        parent_block = bitstream_manager.find_or_create_child_block(
1142	          top_block, tile_inst_name);
1143	        VTR_LOGV(verbose,
1144	                 "Add configurable block '%s' as a child under configurable "
1145	                 "block '%s'\n",
1146	                 tile_inst_name.c_str(),
1147	                 bitstream_manager.block_name(parent_block).c_str());
1148	      }
1149	
1150	      build_physical_block_bitstream(
1151	        bitstream_manager, parent_block, module_manager, module_name_map,
1152	        fabric_tile, curr_tile, circuit_lib, mux_lib, atom_ctx,
1153	        device_annotation, cluster_annotation, place_annotation,
1154	        bitstream_annotation, grids, layer, io_coordinate, io_side,
1155	        unused_mux_config, verbose);
1156	    }
1157	  }
1158	  VTR_LOGV(verbose, "Done\n");
1159	}
1160	
1161	} /* end namespace openfpga */
