1	/********************************************************************
2	 * This file includes functions to build bitstream from global routing
3	 * architecture of a mapped FPGA fabric
4	 * We decode the bitstream from configuration of routing multiplexers
5	 * which locate in global routing architecture
6	 *******************************************************************/
7	#include <algorithm>
8	#include <vector>
9	
10	/* Headers from vtrutil library */
11	#include "vtr_assert.h"
12	#include "vtr_log.h"
13	
14	/* Headers from openfpgautil library */
15	#include "build_mux_bitstream.h"
16	#include "build_routing_bitstream.h"
17	#include "module_manager_utils.h"
18	#include "mux_bitstream_constants.h"
19	#include "mux_utils.h"
20	#include "openfpga_naming.h"
21	#include "openfpga_reserved_words.h"
22	#include "openfpga_rr_graph_utils.h"
23	#include "rr_gsb_edges.h"
24	#include "rr_gsb_utils.h"
25	#include "side_manager.h"
26	
27	/* begin namespace openfpga */
28	namespace openfpga {
29	
30	/********************************************************************
31	 * This function generates bitstream for a routing multiplexer
32	 * This function will identify if a node indicates a routing multiplexer
33	 * If not a routing multiplexer, no bitstream is needed here
34	 * If yes, we will generate the bitstream for the routing multiplexer
35	 *******************************************************************/
36	static void build_switch_block_mux_bitstream(
37	  BitstreamManager& bitstream_manager, const ConfigBlockId& mux_mem_block,
38	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
39	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
40	  const RRGraphView& rr_graph, const RRGraphInEdges& in_edges,
41	  const RRNodeId& cur_rr_node, const std::vector<RRNodeId>& drive_rr_nodes,
42	  const std::vector<RREdgeId>& /*driver_rr_edges*/, const AtomContext& atom_ctx,
43	  const VprDeviceAnnotation& device_annotation,
44	  const VprRoutingAnnotation& routing_annotation,
45	  const std::string& unused_mux_config, const bool& verbose) {
46	  /* Check current rr_node is CHANX or CHANY*/
47	  VTR_ASSERT((e_rr_type::CHANX == rr_graph.node_type(cur_rr_node)) ||
48	             (e_rr_type::CHANY == rr_graph.node_type(cur_rr_node)));
49	
50	  /* Find the input size of the implementation of a routing multiplexer */
51	  size_t datapath_mux_size = drive_rr_nodes.size();
52	
53	  /* Cache input and output nets */
54	  std::vector<ClusterNetId> input_nets;
55	  ClusterNetId output_net = routing_annotation.rr_node_net(cur_rr_node);
56	  for (size_t inode = 0; inode < drive_rr_nodes.size(); ++inode) {
57	    input_nets.push_back(routing_annotation.rr_node_net(drive_rr_nodes[inode]));
58	  }
59	  VTR_ASSERT(input_nets.size() == drive_rr_nodes.size());
60	
61	  /* Find the circuit model id of the mux, we need its design technology which
62	   * matters the bitstream generation */
63	  std::vector<RRSwitchId> driver_switches =
64	    get_rr_graph_driver_switches(rr_graph, in_edges, cur_rr_node);
65	  VTR_ASSERT_MSG(1 <= driver_switches.size(),
66	                 ("There should be at least one driver switch for " +
67	                  std::to_string(size_t(cur_rr_node)))
68	                   .c_str());
69	  /* Iterate over driver switches to find a common switch that can be used */
70	  CircuitModelId switch_index =
71	    device_annotation.rr_switch_circuit_model(driver_switches[0]);
72	  for (size_t i = 1; i < driver_switches.size(); ++i) {
73	    VTR_ASSERT_MSG(device_annotation.rr_switch_circuit_model(
74	                     driver_switches[i]) == switch_index,
75	                   ("All driver switches of " +
76	                    std::to_string(size_t(cur_rr_node)) + " must be the same")
77	                     .c_str());
78	  }
79	  CircuitModelId mux_model =
80	    device_annotation.rr_switch_circuit_model(driver_switches[0]);
81	
82	  /* Find out which routing path is used in this MUX
83	   * Two conditions to be considered:
84	   * - There is no net mapped to cur_rr_node: we use default path id
85	   * - There is a net mapped to cur_rr_node: we find the path id
86	   */
87	  int path_id = DEFAULT_PATH_ID;
88	  VTR_LOGV(verbose, "Prev node '%lu' for src_node '%lu'\n",
89	           size_t(routing_annotation.rr_node_prev_node(cur_rr_node)),
90	           size_t(cur_rr_node));
91	  AtomNetId output_atom_net = atom_ctx.lookup().atom_net(output_net);
92	  if (true == atom_ctx.netlist().valid_net_id(output_atom_net)) {
93	    /* We must have a valid previous node that is supposed to drive the source
94	     * node! */
95	    VTR_ASSERT(routing_annotation.rr_node_prev_node(cur_rr_node));
96	    for (size_t inode = 0; inode < drive_rr_nodes.size(); ++inode) {
97	      VTR_LOGV(verbose, "Path: %lu -> Driver node '%lu' for src_node '%lu'\n",
98	               inode, size_t(drive_rr_nodes[inode]), size_t(cur_rr_node));
99	      if ((input_nets[inode] == output_net) &&
100	          (drive_rr_nodes[inode] ==
101	           routing_annotation.rr_node_prev_node(cur_rr_node))) {
102	        path_id = (int)inode;
103	        break;
104	      }
105	    }
106	  } else if ((unused_mux_config == "unused_input") &&
107	             (false == circuit_lib.mux_add_const_input(mux_model))) {
108	    // If there is no net mapped to this node,
109	    // we will find the first input that is not connected to any net,
110	    // and use it as default path
111	    VTR_LOG(
112	      "At RRNodeId = %d: output is unmapped, try to find an unmapped input as "
113	      "default path\n",
114	      cur_rr_node);
115	    for (int inode = datapath_mux_size - 1; inode >= 0; --inode) {
116	      if (input_nets[inode] == ClusterNetId::INVALID()) {
117	        path_id = inode;
118	        VTR_LOG(
119	          "At RRNodeId = %d: output is unmapped, use unmapped input %d "
120	          "as default path\n",
121	          cur_rr_node, inode);
122	        break;
123	      }
124	    }
125	    if (path_id == DEFAULT_PATH_ID) {
126	      VTR_LOGV_WARN(
127	        verbose,
128	        "At RRNodeId = %d: output is unmapped but all inputs are mapped?",
129	        cur_rr_node);
130	    }
131	  }
132	
133	  /* Ensure that our path id makes sense! */
134	  VTR_ASSERT(
135	    (DEFAULT_PATH_ID == path_id) ||
136	    ((DEFAULT_PATH_ID < path_id) && (path_id < (int)datapath_mux_size)));
137	
138	  /* Generate bitstream depend on both technology and structure of this MUX */
139	  std::vector<bool> mux_bitstream =
140	    build_mux_bitstream(circuit_lib, mux_model, mux_lib, datapath_mux_size,
141	                        path_id, unused_mux_config);
142	
143	  /* Find the module in module manager and ensure the bitstream size matches! */
144	  std::string mem_module_name =
145	    generate_mux_subckt_name(circuit_lib, mux_model, datapath_mux_size,
146	                             std::string(MEMORY_MODULE_POSTFIX));
147	  mem_module_name = module_name_map.name(mem_module_name);
148	  ModuleId mux_mem_module = module_manager.find_module(mem_module_name);
149	  VTR_ASSERT(true == module_manager.valid_module_id(mux_mem_module));
150	  ModulePortId mux_mem_out_port_id = module_manager.find_module_port(
151	    mux_mem_module, generate_configurable_memory_data_out_name());
152	  VTR_ASSERT(mux_bitstream.size() ==
153	             module_manager.module_port(mux_mem_module, mux_mem_out_port_id)
154	               .get_width());
155	
156	  VTR_LOGV(
157	    verbose, "Added %lu bits to '%s' under '%s'\n", mux_bitstream.size(),
158	    bitstream_manager.block_name(mux_mem_block).c_str(),
159	    bitstream_manager.block_name(bitstream_manager.block_parent(mux_mem_block))
160	      .c_str());
161	
162	  /* Add the bistream to the bitstream manager */
163	  bitstream_manager.add_block_bits(mux_mem_block, mux_bitstream);
164	  /* Record path ids, input and output nets */
165	  bitstream_manager.add_path_id_to_block(mux_mem_block, path_id);
166	
167	  /* Add input nets */
168	  bool need_splitter = false;
169	  std::string input_net_ids;
170	  for (const ClusterNetId& input_net : input_nets) {
171	    /* Add a space as a splitter*/
172	    if (true == need_splitter) {
173	      input_net_ids += std::string(" ");
174	    }
175	    AtomNetId input_atom_net = atom_ctx.lookup().atom_net(input_net);
176	    if (true == atom_ctx.netlist().valid_net_id(input_atom_net)) {
177	      input_net_ids += atom_ctx.netlist().net_name(input_atom_net);
178	    } else {
179	      input_net_ids += std::string("unmapped");
180	    }
181	    need_splitter = true;
182	  }
183	  bitstream_manager.add_input_net_id_to_block(mux_mem_block, input_net_ids);
184	
185	  /* Add output nets */
186	  std::string output_net_ids;
187	  if (true == atom_ctx.netlist().valid_net_id(output_atom_net)) {
188	    output_net_ids += atom_ctx.netlist().net_name(output_atom_net);
189	  } else {
190	    output_net_ids += std::string("unmapped");
191	  }
192	  bitstream_manager.add_output_net_id_to_block(mux_mem_block, output_net_ids);
193	}
194	
195	/********************************************************************
196	 * This function generates bitstream for an interconnection,
197	 * i.e., a routing multiplexer, in a Switch Block
198	 * This function will identify if a node indicates a routing multiplexer
199	 * If not a routing multiplexer, no bitstream is needed here
200	 * If yes, we will generate the bitstream for the routing multiplexer
201	 *******************************************************************/
202	static void build_switch_block_interc_bitstream(
203	  BitstreamManager& bitstream_manager,
204	  const ConfigBlockId& sb_configurable_block,
205	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
206	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
207	  const RRGraphView& rr_graph, const RRGraphInEdges& in_edges,
208	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
209	  const VprRoutingAnnotation& routing_annotation, const RRGSB& rr_gsb,
210	  const RRGSBEdges& gsb_edges, const e_side& chan_side,
211	  const size_t& chan_node_id, const std::string& unused_mux_config,
212	  const bool& verbose) {
213	  std::vector<RRNodeId> driver_rr_nodes;
214	
215	  /* Get the node */
216	  const RRNodeId& cur_rr_node = rr_gsb.get_chan_node(chan_side, chan_node_id);
217	
218	  /* Determine if the interc lies inside a channel wire, that is interc between
219	   * segments */
220	  if (false ==
221	      rr_gsb.is_sb_node_passing_wire(rr_graph, chan_side, chan_node_id)) {
222	    driver_rr_nodes = get_rr_gsb_chan_node_configurable_driver_nodes(
223	      rr_graph, in_edges, rr_gsb, gsb_edges, chan_side, chan_node_id);
224	    /* Special: if there are zero-driver nodes. We skip here */
225	    if (0 == driver_rr_nodes.size()) {
226	      return;
227	    }
228	  }
229	
230	  if ((0 == driver_rr_nodes.size()) || (0 == driver_rr_nodes.size())) {
231	    /* No bitstream generation required by a special direct connection*/
232	    return;
233	  } else if (1 < driver_rr_nodes.size()) {
234	    /* Create the block denoting the memory instances that drives this node in
235	     * Switch Block */
236	    std::string mem_block_name = generate_sb_memory_instance_name(
237	      SWITCH_BLOCK_MEM_INSTANCE_PREFIX, chan_side, chan_node_id,
238	      std::string(""));
239	    ConfigBlockId mux_mem_block = bitstream_manager.add_block(mem_block_name);
240	    bitstream_manager.add_child_block(sb_configurable_block, mux_mem_block);
241	    VTR_LOGV(verbose, "Added '%s' under '%s'\n",
242	             bitstream_manager.block_name(mux_mem_block).c_str(),
243	             bitstream_manager.block_name(sb_configurable_block).c_str());
244	    /* This is a routing multiplexer! Generate bitstream */
245	    build_switch_block_mux_bitstream(
246	      bitstream_manager, mux_mem_block, module_manager, module_name_map,
247	      circuit_lib, mux_lib, rr_graph, in_edges, cur_rr_node, driver_rr_nodes,
248	      gsb_edges.get_chan_node_in_edges(rr_gsb, in_edges, chan_side,
249	                                       chan_node_id),
250	      atom_ctx, device_annotation, routing_annotation, unused_mux_config,
251	      verbose);
252	  } /*Nothing should be done else*/
253	}
