400	/********************************************************************
401	 * This function generates bitstream for an interconnection,
402	 * i.e., a routing multiplexer, in a Connection Block
403	 * This function will identify if a node indicates a routing multiplexer
404	 * If not a routing multiplexer, no bitstream is needed here
405	 * If yes, we will generate the bitstream for the routing multiplexer
406	 *******************************************************************/
407	static void build_connection_block_interc_bitstream(
408	  BitstreamManager& bitstream_manager,
409	  const ConfigBlockId& cb_configurable_block,
410	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
411	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
412	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
413	  const VprRoutingAnnotation& routing_annotation, const RRGraphView& rr_graph,
414	  const RRGraphInEdges& in_edges, const RRGSB& rr_gsb,
415	  const RRGSBEdges& gsb_edges, const e_side& cb_ipin_side,
416	  const size_t& ipin_index, const std::string& unused_mux_config,
417	  const bool& verbose) {
418	  RRNodeId src_rr_node = rr_gsb.get_ipin_node(cb_ipin_side, ipin_index);
419	
420	  VTR_LOGV(verbose, "\tGenerating bitstream for IPIN '%lu'. Details: %s\n",
421	           ipin_index, rr_graph.node_coordinate_to_string(src_rr_node).c_str());
422	
423	  /* Consider configurable edges only */
424	  std::vector<RREdgeId> driver_rr_edges = gsb_edges.get_ipin_node_in_edges(
425	    rr_gsb, in_edges, cb_ipin_side, ipin_index);
426	  std::vector<RRNodeId> driver_rr_nodes;
427	  for (const RREdgeId curr_edge : driver_rr_edges) {
428	    driver_rr_nodes.push_back(rr_graph.edge_src_node(curr_edge));
429	  }
430	
431	  if (1 == driver_rr_nodes.size()) {
432	    /* No bitstream generation required by a special direct connection*/
433	  } else if (1 < driver_rr_nodes.size()) {
434	    /* Create the block denoting the memory instances that drives this node in
435	     * Switch Block */
436	    std::string mem_block_name = generate_cb_memory_instance_name(
437	      CONNECTION_BLOCK_MEM_INSTANCE_PREFIX,
438	      get_rr_graph_single_node_side(rr_graph, src_rr_node), ipin_index,
439	      std::string(""));
440	    ConfigBlockId mux_mem_block = bitstream_manager.add_block(mem_block_name);
441	    bitstream_manager.add_child_block(cb_configurable_block, mux_mem_block);
442	    VTR_LOGV(verbose, "Added '%s' under '%s'\n",
443	             bitstream_manager.block_name(mux_mem_block).c_str(),
444	             bitstream_manager.block_name(cb_configurable_block).c_str());
445	    /* This is a routing multiplexer! Generate bitstream */
446	    build_connection_block_mux_bitstream(
447	      bitstream_manager, mux_mem_block, module_manager, module_name_map,
448	      circuit_lib, mux_lib, atom_ctx, device_annotation, routing_annotation,
449	      rr_graph, in_edges, rr_gsb, gsb_edges, cb_ipin_side, ipin_index,
450	      unused_mux_config, verbose);
451	  } /*Nothing should be done else*/
452	}
