454	/********************************************************************
455	 * This function generates bitstream for a Switch Block
456	 * and add it to the bitstream manager
457	 * This function will spot all the routing multiplexers in a Switch Block
458	 * using a simple but effective rule:
459	 * The fan-in of each output node.
460	 * If there are more than 2 fan-in, there is a routing multiplexer
461	 *
462	 * Note that the output nodes typically spread over all the sides of a Switch
463	 *Block So, we will iterate over that.
464	 *******************************************************************/
465	static void build_switch_block_bitstream(
466	  BitstreamManager& bitstream_manager, const ConfigBlockId& sb_config_block,
467	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
468	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
469	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
470	  const VprRoutingAnnotation& routing_annotation, const RRGraphView& rr_graph,
471	  const RRGraphInEdges& in_edges, const RRGSB& rr_gsb,
472	  const RRGSBEdges& gsb_edges, const std::string& unused_mux_config,
473	  const bool& verbose) {
474	  /* Iterate over all the multiplexers */
475	  for (size_t side = 0; side < rr_gsb.get_num_sides(); ++side) {
476	    SideManager side_manager(side);
477	    for (size_t itrack = 0;
478	         itrack < rr_gsb.get_chan_width(side_manager.get_side()); ++itrack) {
479	      VTR_ASSERT((e_rr_type::CHANX == rr_graph.node_type(rr_gsb.get_chan_node(
480	                                        side_manager.get_side(), itrack))) ||
481	                 (e_rr_type::CHANY == rr_graph.node_type(rr_gsb.get_chan_node(
482	                                        side_manager.get_side(), itrack))));
483	      /* Only output port indicates a routing multiplexer */
484	      if (OUT_PORT !=
485	          rr_gsb.get_chan_node_direction(side_manager.get_side(), itrack)) {
486	        continue;
487	      }
488	      build_switch_block_interc_bitstream(
489	        bitstream_manager, sb_config_block, module_manager, module_name_map,
490	        circuit_lib, mux_lib, rr_graph, in_edges, atom_ctx, device_annotation,
491	        routing_annotation, rr_gsb, gsb_edges, side_manager.get_side(), itrack,
492	        unused_mux_config, verbose);
493	    }
494	    if (true == module_manager.group_routing()) {
495	      // If routing is grouped, we need to generate bitstream for IPINs in
496	      // switch blocks as well since they are in the same module with the
497	      // routing multiplexers
498	      for (size_t inode = 0;
499	           inode < rr_gsb.get_num_ipin_nodes(side_manager.get_side());
500	           ++inode) {
501	        VTR_LOGV(verbose, "\tGenerating bitstream for IPIN at '%s' side\n",
502	                 side_manager.to_string().c_str());
503	
504	        build_connection_block_interc_bitstream(
505	          bitstream_manager, sb_config_block, module_manager, module_name_map,
506	          circuit_lib, mux_lib, atom_ctx, device_annotation, routing_annotation,
507	          rr_graph, in_edges, rr_gsb, gsb_edges, side_manager.get_side(), inode,
508	          unused_mux_config, verbose);
509	      }
510	    }
511	  }
512	}
