514	/********************************************************************
515	 * This function generates bitstream for a Connection Block
516	 * and add it to the bitstream manager
517	 * This function will spot all the routing multiplexers in a Connection Block
518	 * using a simple but effective rule:
519	 * The fan-in of each output node.
520	 * If there are more than 2 fan-in, there is a routing multiplexer
521	 *
522	 * Note that the output nodes are the IPIN rr node in a Connection Block
523	 * So, we will iterate over that.
524	 *******************************************************************/
525	static void build_connection_block_bitstream(
526	  BitstreamManager& bitstream_manager,
527	  const ConfigBlockId& cb_configurable_block,
528	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
529	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
530	  const AtomContext& atom_ctx, const VprDeviceAnnotation& device_annotation,
531	  const VprRoutingAnnotation& routing_annotation, const RRGraphView& rr_graph,
532	  const RRGraphInEdges& in_edges, const RRGSB& rr_gsb,
533	  const RRGSBEdges& gsb_edges, const e_rr_type& cb_type,
534	  const std::string& unused_mux_config, const bool& verbose) {
535	  /* Find routing multiplexers on the sides of a Connection block where IPIN
536	   * nodes locate */
537	  std::vector<enum e_side> cb_sides = rr_gsb.get_cb_ipin_sides(cb_type);
538	
539	  for (size_t side = 0; side < cb_sides.size(); ++side) {
540	    enum e_side cb_ipin_side = cb_sides[side];
541	    SideManager side_manager(cb_ipin_side);
542	    for (size_t inode = 0; inode < rr_gsb.get_num_ipin_nodes(cb_ipin_side);
543	         ++inode) {
544	      VTR_LOGV(verbose, "\tGenerating bitstream for IPIN at '%s' side\n",
545	               side_manager.to_string().c_str());
546	      build_connection_block_interc_bitstream(
547	        bitstream_manager, cb_configurable_block, module_manager,
548	        module_name_map, circuit_lib, mux_lib, atom_ctx, device_annotation,
549	        routing_annotation, rr_graph, in_edges, rr_gsb, gsb_edges, cb_ipin_side,
550	        inode, unused_mux_config, verbose);
551	    }
552	  }
553	}
