555	/********************************************************************
556	 * Create bitstream for a X-direction or Y-direction Connection Blocks
557	 *******************************************************************/
558	static void build_connection_block_bitstreams(
559	  BitstreamManager& bitstream_manager,
560	  const ConfigBlockId& top_configurable_block,
561	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
562	  const FabricTile& fabric_tile, const CircuitLibrary& circuit_lib,
563	  const MuxLibrary& mux_lib, const AtomContext& atom_ctx,
564	  const VprDeviceAnnotation& device_annotation,
565	  const VprRoutingAnnotation& routing_annotation, const RRGraphView& rr_graph,
566	  const RRGraphInEdges& in_edges, const DeviceRRGSB& device_rr_gsb,
567	  const bool& compact_routing_hierarchy, const e_rr_type& cb_type,
568	  const std::string& unused_mux_config, const bool& verbose) {
569	  vtr::Point<size_t> cb_range = device_rr_gsb.get_gsb_range();
570	
571	  for (size_t ix = 0; ix < cb_range.x(); ++ix) {
572	    for (size_t iy = 0; iy < cb_range.y(); ++iy) {
573	      const RRGSB& rr_gsb = device_rr_gsb.get_gsb(ix, iy);
574	      /* Check if the connection block exists in the device!
575	       * Some of them do NOT exist due to heterogeneous blocks (height > 1)
576	       * We will skip those modules
577	       */
578	      if (false == rr_gsb.is_cb_exist(cb_type)) {
579	        continue;
580	      }
581	      /* Skip if the cb does not contain any configuration bits! */
582	      if (true ==
583	          connection_block_contain_only_routing_tracks(rr_gsb, cb_type)) {
584	        VTR_LOGV(verbose,
585	                 "\n\tSkipped %s Connection Block [%lu][%lu] as it contains "
586	                 "only routing tracks\n",
587	                 cb_type == e_rr_type::CHANX ? "X-direction" : "Y-direction",
588	                 rr_gsb.get_cb_x(cb_type), rr_gsb.get_cb_y(cb_type));
589	        continue;
590	      }
591	
592	      VTR_LOGV(verbose,
593	               "\n\tGenerating bitstream for %s Connection Block [%lu][%lu]\n",
594	               cb_type == e_rr_type::CHANX ? "X-direction" : "Y-direction",
595	               rr_gsb.get_cb_x(cb_type), rr_gsb.get_cb_y(cb_type));
596	
597	      /* Find the cb module so that we can precisely reserve child blocks */
598	      vtr::Point<size_t> cb_coord(rr_gsb.get_cb_x(cb_type),
599	                                  rr_gsb.get_cb_y(cb_type));
600	      std::string cb_module_name =
601	        generate_connection_block_module_name(cb_type, cb_coord);
602	      if (true == compact_routing_hierarchy) {
603	        vtr::Point<size_t> unique_cb_coord(ix, iy);
604	        /* Note: use GSB coordinate when inquire for unique modules!!! */
605	        const RRGSB& unique_mirror =
606	          device_rr_gsb.get_cb_unique_module(cb_type, unique_cb_coord);
607	        unique_cb_coord.set_x(unique_mirror.get_cb_x(cb_type));
608	        unique_cb_coord.set_y(unique_mirror.get_cb_y(cb_type));
609	        cb_module_name =
610	          generate_connection_block_module_name(cb_type, unique_cb_coord);
611	      }
612	      ModuleId cb_module =
613	        module_manager.find_module(module_name_map.name(cb_module_name));
614	      VTR_ASSERT(true == module_manager.valid_module_id(cb_module));
615	
616	      /* Bypass empty blocks which have none configurable children */
617	      if (0 == count_module_manager_module_configurable_children(
618	                 module_manager, cb_module,
619	                 ModuleManager::e_config_child_type::LOGICAL) &&
620	          0 == count_module_manager_module_configurable_children(
621	                 module_manager, cb_module,
622	                 ModuleManager::e_config_child_type::PHYSICAL)) {
623	        continue;
624	      }
625	
626	      /* TODO: If the fabric tile is not empty, find the tile module and create
627	       * the block accordingly. Also to support future hierarchy changes, when
628	       * creating the blocks, trace backward until reach the current top block.
629	       * If any block is missing during the back tracing, create it. */
630	      ConfigBlockId parent_block = top_configurable_block;
631	      FabricTileId curr_tile = fabric_tile.find_tile_by_cb_coordinate(
632	        cb_type, vtr::Point<size_t>(ix, iy));
633	      ConfigBlockId cb_configurable_block;
634	      if (fabric_tile.valid_tile_id(curr_tile)) {
635	        vtr::Point<size_t> tile_coord = fabric_tile.tile_coordinate(curr_tile);
636	        std::string tile_inst_name = generate_tile_module_name(tile_coord);
637	        parent_block = bitstream_manager.find_or_create_child_block(
638	          top_configurable_block, tile_inst_name);
639	        /* For tile modules, need to find the specific instance name under its
640	         * unique tile */
641	        vtr::Point<size_t> cb_coord_in_unique_tile =
642	          fabric_tile.find_cb_coordinate_in_unique_tile(
643	            curr_tile, cb_type, vtr::Point<size_t>(ix, iy));
644	        const RRGSB& unique_tile_cb_rr_gsb =
645	          device_rr_gsb.get_gsb(cb_coord_in_unique_tile);
646	        cb_configurable_block =
647	          bitstream_manager.add_block(generate_connection_block_module_name(
648	            cb_type, unique_tile_cb_rr_gsb.get_cb_coordinate(cb_type)));
649	      } else {
650	        /* Create a block for the bitstream which corresponds to the Switch
651	         * block
652	         */
653	        cb_configurable_block = bitstream_manager.add_block(
654	          generate_connection_block_module_name(cb_type, cb_coord));
655	      }
656	      /* Set switch block as a child of top block */
657	      bitstream_manager.add_child_block(parent_block, cb_configurable_block);
658	
659	      /* Reserve child blocks for new created block */
660	      bitstream_manager.reserve_child_blocks(
661	        cb_configurable_block,
662	        count_module_manager_module_configurable_children(
663	          module_manager, cb_module,
664	          ModuleManager::e_config_child_type::PHYSICAL));
665	
666	      /* Create a dedicated block for the non-unified configurable child */
667	      if (!module_manager.unified_configurable_children(cb_module)) {
668	        VTR_ASSERT(1 ==
669	                   module_manager
670	                     .configurable_children(
671	                       cb_module, ModuleManager::e_config_child_type::PHYSICAL)
672	                     .size());
673	        std::string phy_mem_instance_name = module_manager.instance_name(
674	          cb_module,
675	          module_manager.configurable_children(
676	            cb_module, ModuleManager::e_config_child_type::PHYSICAL)[0],
677	          module_manager.configurable_child_instances(
678	            cb_module, ModuleManager::e_config_child_type::PHYSICAL)[0]);
679	        ConfigBlockId cb_grouped_config_block =
680	          bitstream_manager.add_block(phy_mem_instance_name);
681	        bitstream_manager.add_child_block(cb_configurable_block,
682	                                          cb_grouped_config_block);
683	        VTR_LOGV(verbose, "Added '%s' as a child to '%s'\n",
684	                 bitstream_manager.block_name(cb_grouped_config_block).c_str(),
685	                 bitstream_manager.block_name(cb_configurable_block).c_str());
686	        cb_configurable_block = cb_grouped_config_block;
687	      }
688	
689	      build_connection_block_bitstream(
690	        bitstream_manager, cb_configurable_block, module_manager,
691	        module_name_map, circuit_lib, mux_lib, atom_ctx, device_annotation,
692	        routing_annotation, rr_graph, in_edges, rr_gsb,
693	        device_rr_gsb.get_gsb_edges(ix, iy), cb_type, unused_mux_config,
694	        verbose);
695	
696	      VTR_LOGV(verbose, "\tDone\n");
697	    }
698	  }
699	}
700	
701	/********************************************************************
702	 * Top-level function to create bitstream for global routing architecture
703	 * Two major tasks:
704	 * 1. Generate bitstreams for Switch Blocks
705	 * 2. Generate bitstreams for both X-direction and Y-direction Connection Blocks
706	 *******************************************************************/
707	void build_routing_bitstream(
708	  BitstreamManager& bitstream_manager,
709	  const ConfigBlockId& top_configurable_block,
710	  const ModuleManager& module_manager, const ModuleNameMap& module_name_map,
711	  const FabricTile& fabric_tile, const CircuitLibrary& circuit_lib,
712	  const MuxLibrary& mux_lib, const AtomContext& atom_ctx,
713	  const VprDeviceAnnotation& device_annotation,
714	  const VprRoutingAnnotation& routing_annotation, const RRGraphView& rr_graph,
715	  const RRGraphInEdges& in_edges, const DeviceRRGSB& device_rr_gsb,
716	  const bool& compact_routing_hierarchy, const std::string& unused_mux_config,
717	  const bool& verbose) {
718	  /* Generate bitstream for each switch blocks
719	   * To organize the bitstream in blocks, we create a block for each switch
720	   * block and give names which are same as they are in top-level module
721	   * managers
722	   */
723	  VTR_LOG("Generating bitstream for Switch blocks...");
724	  vtr::Point<size_t> sb_range = device_rr_gsb.get_gsb_range();
725	  for (size_t ix = 0; ix < sb_range.x(); ++ix) {
726	    for (size_t iy = 0; iy < sb_range.y(); ++iy) {
727	      const RRGSB& rr_gsb = device_rr_gsb.get_gsb(ix, iy);
728	      const RRGSBEdges& gsb_edges = device_rr_gsb.get_gsb_edges(ix, iy);
729	      /* Check if the switch block exists in the device!
730	       * Some of them do NOT exist due to heterogeneous blocks (width > 1)
731	       * We will skip those modules
732	       */
733	      if (false == gsb_edges.is_sb_exist(rr_gsb)) {
734	        continue;
735	      }
736	
737	      VTR_LOGV(verbose,
738	               "\n\tGenerating bitstream for Switch blocks[%lu][%lu]...\n", ix,
739	               iy);
740	
741	      vtr::Point<size_t> sb_coord(rr_gsb.get_sb_x(), rr_gsb.get_sb_y());
742	
743	      /* Find the sb module so that we can precisely reserve child blocks */
744	      std::string sb_module_name = generate_switch_block_module_name(sb_coord);
745	      if (true == compact_routing_hierarchy) {
746	        vtr::Point<size_t> unique_sb_coord(ix, iy);
747	        const RRGSB& unique_mirror =
748	          device_rr_gsb.get_sb_unique_module(sb_coord);
749	        unique_sb_coord.set_x(unique_mirror.get_sb_x());
750	        unique_sb_coord.set_y(unique_mirror.get_sb_y());
751	        sb_module_name = generate_switch_block_module_name(unique_sb_coord);
752	      }
753	      ModuleId sb_module =
754	        module_manager.find_module(module_name_map.name(sb_module_name));
755	      VTR_ASSERT(true == module_manager.valid_module_id(sb_module));
756	
757	      /* Bypass empty blocks which have none configurable children */
758	      if (0 == count_module_manager_module_configurable_children(
759	                 module_manager, sb_module,
760	                 ModuleManager::e_config_child_type::LOGICAL) &&
761	          0 == count_module_manager_module_configurable_children(
762	                 module_manager, sb_module,
763	                 ModuleManager::e_config_child_type::PHYSICAL)) {
764	        continue;
765	      }
766	
767	      /* TODO: If the fabric tile is not empty, find the tile module and create
768	       * the block accordingly. Also to support future hierarchy changes, when
769	       * creating the blocks, trace backward until reach the current top block.
770	       * If any block is missing during the back tracing, create it. */
771	      ConfigBlockId parent_block = top_configurable_block;
772	      FabricTileId curr_tile = fabric_tile.find_tile_by_sb_coordinate(sb_coord);
773	      ConfigBlockId sb_configurable_block;
774	      if (fabric_tile.valid_tile_id(curr_tile)) {
775	        vtr::Point<size_t> tile_coord = fabric_tile.tile_coordinate(curr_tile);
776	        std::string tile_inst_name = generate_tile_module_name(tile_coord);
777	        parent_block = bitstream_manager.find_or_create_child_block(
778	          top_configurable_block, tile_inst_name);
779	        /* For tile modules, need to find the specific instance name under its
780	         * unique tile */
781	        vtr::Point<size_t> sb_coord_in_unique_tile =
782	          fabric_tile.find_sb_coordinate_in_unique_tile(curr_tile, sb_coord);
783	        sb_configurable_block = bitstream_manager.add_block(
784	          generate_switch_block_module_name(sb_coord_in_unique_tile));
785	      } else {
786	        /* Create a block for the bitstream which corresponds to the Switch
787	         * block
788	         */
789	        sb_configurable_block = bitstream_manager.add_block(
790	          generate_switch_block_module_name(sb_coord));
791	      }
792	      /* Set switch block as a child of top block */
793	      bitstream_manager.add_child_block(parent_block, sb_configurable_block);
794	
795	      /* Reserve child blocks for new created block */
796	      bitstream_manager.reserve_child_blocks(
797	        sb_configurable_block,
798	        count_module_manager_module_configurable_children(
799	          module_manager, sb_module,
800	          ModuleManager::e_config_child_type::PHYSICAL));
801	
802	      /* Create a dedicated block for the non-unified configurable child */
803	      if (!module_manager.unified_configurable_children(sb_module)) {
804	        VTR_ASSERT(1 ==
805	                   module_manager
806	                     .configurable_children(
807	                       sb_module, ModuleManager::e_config_child_type::PHYSICAL)
808	                     .size());
809	        std::string phy_mem_instance_name = module_manager.instance_name(
810	          sb_module,
811	          module_manager.configurable_children(
812	            sb_module, ModuleManager::e_config_child_type::PHYSICAL)[0],
813	          module_manager.configurable_child_instances(
814	            sb_module, ModuleManager::e_config_child_type::PHYSICAL)[0]);
815	        ConfigBlockId sb_grouped_config_block =
816	          bitstream_manager.add_block(phy_mem_instance_name);
817	        bitstream_manager.add_child_block(sb_configurable_block,
818	                                          sb_grouped_config_block);
819	        VTR_LOGV(verbose, "Added '%s' as a child to '%s'\n",
820	                 bitstream_manager.block_name(sb_grouped_config_block).c_str(),
821	                 bitstream_manager.block_name(sb_configurable_block).c_str());
822	        sb_configurable_block = sb_grouped_config_block;
823	      }
824	
825	      build_switch_block_bitstream(
826	        bitstream_manager, sb_configurable_block, module_manager,
827	        module_name_map, circuit_lib, mux_lib, atom_ctx, device_annotation,
828	        routing_annotation, rr_graph, in_edges, rr_gsb, gsb_edges,
829	        unused_mux_config, verbose);
830	
831	      VTR_LOGV(verbose, "\tDone\n");
832	    }
833	  }
834	  VTR_LOG("Done\n");
835	
836	  if (true == module_manager.group_routing()) {
837	    VTR_LOG(
838	      "Skip generating bitstream for Connection blocks since they are "
839	      "grouped with Switch blocks in the same module\n");
840	    return;
841	  }
842	  /* Generate bitstream for each connection blocks
843	   * To organize the bitstream in blocks, we create a block for each connection
844	   * block and give names which are same as they are in top-level module
845	   * managers
846	   */
847	  VTR_LOG("Generating bitstream for X-direction Connection blocks ...");
848	
849	  build_connection_block_bitstreams(
850	    bitstream_manager, top_configurable_block, module_manager, module_name_map,
851	    fabric_tile, circuit_lib, mux_lib, atom_ctx, device_annotation,
852	    routing_annotation, rr_graph, in_edges, device_rr_gsb,
853	    compact_routing_hierarchy, e_rr_type::CHANX, unused_mux_config, verbose);
854	  VTR_LOG("Done\n");
855	
856	  VTR_LOG("Generating bitstream for Y-direction Connection blocks ...");
857	
858	  build_connection_block_bitstreams(
859	    bitstream_manager, top_configurable_block, module_manager, module_name_map,
860	    fabric_tile, circuit_lib, mux_lib, atom_ctx, device_annotation,
861	    routing_annotation, rr_graph, in_edges, device_rr_gsb,
862	    compact_routing_hierarchy, e_rr_type::CHANY, unused_mux_config, verbose);
863	  VTR_LOG("Done\n");
864	}
865	
866	} /* end namespace openfpga */
