90	  /* Find the path_id related to the implementation */
91	  if (DEFAULT_PATH_ID == path_id) {
92	    datapath_id = find_mux_default_path_id(
93	      circuit_lib, mux_model, implemented_mux_size, unused_mux_config);
94	  } else {
95	    VTR_ASSERT(datapath_id < mux_size);
96	  }
97	  /* Path id should makes sense */
98	  VTR_ASSERT(datapath_id < mux_graph.inputs().size());
99	  /* We should have only one output for this MUX! */
100	  VTR_ASSERT(1 == mux_graph.outputs().size());
101	
102	  /* Generate the memory bits */
103	  vtr::vector<MuxMemId, bool> raw_bitstream = mux_graph.decode_memory_bits(
104	    MuxInputId(datapath_id), mux_graph.output_id(mux_graph.outputs()[0]));
105	
106	  std::vector<bool> mux_bitstream;
107	  for (const bool& bit : raw_bitstream) {
108	    mux_bitstream.push_back(bit);
109	  }
110	
111	  /* Consider local encoder support, we need further encode the bitstream */
112	  if (false == circuit_lib.mux_use_local_encoder(mux_model)) {
113	    return mux_bitstream;
114	  }
115	
116	  /* Clear the mux_bitstream, we need to apply encoding */
117	  mux_bitstream.clear();
118	
119	  /* Encode the memory bits level by level,
120	   * One local encoder is used for each level of multiplexers
121	   */
122	  for (const size_t& level : mux_graph.levels()) {
123	    /* The encoder will convert the path_id to a binary number
124	     * For example: when path_id=3 (use the 4th input), using a 2-input encoder
